using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ── 1. Strongly-typed metadata ──────────────────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Type:       {personInfo.Type.Name}");
Console.WriteLine($"Properties: {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");
Console.WriteLine();

// ── 2. Probe without throwing ───────────────────────────────────────
// TryGetTypeInfo returns false instead of throwing when metadata
// isn't available (e.g. the resolver doesn't handle the type).
var restricted = new JsonSerializerOptions
{
    // resolver that only knows about Person
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            ti =>
            {
                if (ti.Type != typeof(Person))
                    throw new NotSupportedException($"Nope: {ti.Type.Name}");
            }
        }
    }
};

if (restricted.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"[probe] Person metadata found  → {found!.Type.Name}");
else
    Console.WriteLine("[probe] Person metadata NOT found");

if (restricted.TryGetTypeInfo(typeof(int), out _))
    Console.WriteLine("[probe] int metadata found");
else
    Console.WriteLine("[probe] int metadata NOT found  → no exception thrown!");

